 179→/// User-provided mock override from `.shatter/config.yaml`.
 180→#[derive(Debug, Clone, PartialEq, serde::Deserialize, serde::Serialize)]
 181→pub struct MockOverride {
 182→    /// Pre-configured return values, replacing auto-generated defaults.
 183→    #[serde(default)]
 184→    pub return_values: Option<Vec<Value>>,
 185→    /// Override the default behavior.
 186→    #[serde(default)]
 187→    pub behavior: Option<MockBehavior>,
 188→}
 189→
 190→/// Generate auto-mocks for all dependencies of a function.
 191→///
 192→/// Returns mock configs for dependencies that:
 193→/// 1. Are not already covered by `existing_mocks` (e.g., behavior-map mocks)
 194→/// 2. Are classified as Mock (not Passthrough or Analyze) by the scope matcher
 195→///
 196→/// User overrides from config take precedence over auto-generated defaults.
 197→pub fn generate_auto_mocks(
 198→    deps: &[ExternalDependency],
 199→    scope: Option<&ScopeMatcher>,
 200→    overrides: &HashMap<String, MockOverride>,
 201→    existing_mocks: &[MockConfig],
 202→) -> Vec<MockConfig> {
 203→    let already_mocked: std::collections::HashSet<&str> = existing_mocks
 204→        .iter()
 205→        .map(|m| m.symbol.as_str())
 206→        .collect();
 207→
 208→    let mut result = Vec::new();
 209→
 210→    for dep in deps {
 211→        // Skip if already covered by a behavior-map mock
 212→        if already_mocked.contains(dep.symbol.as_str()) {
 213→            continue;
 214→        }
 215→
 216→        // Check scope: if Passthrough, skip; if Analyze (no rule), use category logic
 217→        if let Some(matcher) = scope {
 218→            match matcher.classify_dependency(&dep.symbol) {
 219→                DependencyAction::Passthrough => continue,
 220→                DependencyAction::Mock | DependencyAction::Analyze => {}
 221→            }
 222→        }
 223→
 224→        let category = classify_dependency(dep);
 225→
 226→        // Pure utilities default to passthrough — skip generating a mock
 227→        if category == IoCategory::PureUtility && !overrides.contains_key(&dep.symbol) {
 228→            continue;
 229→        }
 230→
 231→        let mut mock = generate_default_mock(dep, category);
 232→
 233→        // Apply user overrides
 234→        if let Some(ov) = overrides.get(&dep.symbol) {
 235→            if let Some(ref vals) = ov.return_values {
 236→                mock.return_values = vals.clone();
 237→            }
 238→            if let Some(ref behavior) = ov.behavior {
 239→                mock.default_behavior = behavior.clone();
 240→            }
 241→        }
 242→
 243→        result.push(mock);
 244→    }
 245→
 246→    result
 247→}
 248→
 249→// ---------------------------------------------------------------------------
 250→// Error variant generation
 251→// ---------------------------------------------------------------------------
 252→
 253→/// Generate a [`MockConfig`] that throws an error, producing a realistic
 254→/// error shape based on the dependency's return type and I/O category.
 255→///
 256→/// Dispatch order:
 257→/// 1. Object with a `"status"` field → HTTP 400/500 error objects
 258→/// 2. Nullable → `null` (represents a "not found" / absent value)
 259→/// 3. Category-aware: Network → HTTP error, Database → connection error,
 260→///    FileSystem → ENOENT
 261→/// 4. Fallback → `ThrowError` behavior with an empty return_values vec
 262→pub fn generate_error_variant(dep: &ExternalDependency, category: IoCategory) -> MockConfig {
 263→    // Check for object with "status" field → HTTP error responses
 264→    if let TypeInfo::Object { fields } = &dep.return_type
 265→        && fields.iter().any(|(name, _)| name == "status")
 266→    {
 267→        return MockConfig {
 268→            symbol: dep.symbol.clone(),
 269→            return_values: vec![
 270→                json!({"status": 400, "error": "Bad Request"}),
 271→                json!({"status": 500, "error": "Internal Server Error"}),
 272→            ],
 273→            should_track_calls: true,
 274→            default_behavior: MockBehavior::RepeatLast,
 275→        };
 276→    }
 277→
 278→    // Nullable → null (represents absence / not-found)
 279→    if matches!(&dep.return_type, TypeInfo::Nullable { .. }) {
 280→        return MockConfig {
 281→            symbol: dep.symbol.clone(),
 282→            return_values: vec![Value::Null],
 283→            should_track_calls: true,
 284→            default_behavior: MockBehavior::RepeatLast,
 285→        };
 286→    }
 287→
 288→    // Category-aware error shapes
 289→    match category {
 290→        IoCategory::Network => MockConfig {
 291→            symbol: dep.symbol.clone(),
 292→            return_values: vec![
 293→                json!({"status": 500, "error": "Internal Server Error"}),
 294→                json!({"status": 503, "error": "Service Unavailable"}),
 295→            ],
 296→            should_track_calls: true,
 297→            default_behavior: MockBehavior::ThrowError,
 298→        },
 299→        IoCategory::Database => MockConfig {
 300→            symbol: dep.symbol.clone(),
 301→            return_values: vec![
 302→                json!({"code": "ECONNREFUSED", "message": "Connection refused"}),
 303→            ],
 304→            should_track_calls: true,
 305→            default_behavior: MockBehavior::ThrowError,
 306→        },
 307→        IoCategory::FileSystem => MockConfig {
 308→            symbol: dep.symbol.clone(),
 309→            return_values: vec![
 310→                json!({"code": "ENOENT", "message": "No such file or directory"}),
 311→            ],
 312→            should_track_calls: true,
 313→            default_behavior: MockBehavior::ThrowError,
 314→        },
 315→        // Fallback: bare ThrowError with no pre-configured return values
 316→        IoCategory::PureUtility | IoCategory::ExternalOther => MockConfig {
 317→            symbol: dep.symbol.clone(),
 318→            return_values: vec![],
 319→            should_track_calls: true,
 320→            default_behavior: MockBehavior::ThrowError,
 321→        },
 322→    }
 323→}
 324→
 325→/// Generate error-variant [`MockConfig`]s for dependencies that should
 326→/// exercise error-handling paths.
 327→///
 328→/// Uses `error_probability` to decide per-dependency whether to generate an
 329→/// error mock. Dependencies already covered by `existing_mocks` or marked
 330→/// as passthrough are skipped. Pure utilities are always skipped.
 331→pub fn generate_error_mocks(
 332→    deps: &[ExternalDependency],
 333→    scope: Option<&ScopeMatcher>,
 334→    existing_mocks: &[MockConfig],
 335→    error_probability: f64,
 336→    rng: &mut impl rand::Rng,
 337→) -> Vec<MockConfig> {
 338→    let already_mocked: std::collections::HashSet<&str> = existing_mocks
 339→        .iter()
 340→        .map(|m| m.symbol.as_str())
 341→        .collect();
 342→
 343→    let mut result = Vec::new();
 344→
 345→    for dep in deps {
 346→        if already_mocked.contains(dep.symbol.as_str()) {
 347→            continue;
 348→        }
 349→
 350→        if let Some(matcher) = scope
 351→            && matches!(
 352→                matcher.classify_dependency(&dep.symbol),
 353→                DependencyAction::Passthrough
 354→            )
 355→        {
 356→            continue;
 357→        }
 358→
 359→        let category = classify_dependency(dep);
 360→        if category == IoCategory::PureUtility {
 361→            continue;
 362→        }
 363→
 364→        if rng.random_bool(error_probability.clamp(0.0, 1.0)) {
 365→            result.push(generate_error_variant(dep, category));
 366→        }
 367→    }
 368→
 369→    result
 370→}
 371→
 372→/// Where a mock's return value originated.
 373→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 374→pub enum ValueSource {
 375→    /// Generated automatically from dependency classification and type info.
 376→    AutoGenerated,
 377→    /// Overridden by the user via `.shatter/config.yaml`.
 378→    UserOverride,
 379→    /// Inherited from an existing behavior-map mock.
 380→    BehaviorMap,
 381→}
 382→
 383→/// A resolved mock parameter ready for the orchestrator, combining dependency
 384→/// metadata with its mock configuration.
 385→#[derive(Debug, Clone, PartialEq)]
 386→pub struct MockParam {
 387→    /// Fully qualified symbol name of the mocked dependency.
 388→    pub symbol: String,
 389→    /// Return type of the dependency (used for value generation).
 390→    pub return_type: TypeInfo,
 391→    /// Classified I/O category.
 392→    pub category: IoCategory,
 393→    /// Estimated number of calls based on static call-site count.
 394→    pub call_count_estimate: u32,
 395→    /// Where the mock's return value came from.
 396→    pub value_source: ValueSource,
 397→}
 398→
 399→/// Build [`MockParam`]s from dependencies and their resolved mock configs.
 400→///
 401→/// Filters out dependencies whose category is [`IoCategory::PureUtility`]
 402→/// unless a matching config explicitly overrides them. Dependencies with
 403→/// a matching config get [`ValueSource::UserOverride`]; those without get
 404→/// [`ValueSource::AutoGenerated`].
 405→pub fn build_mock_params(
 406→    deps: &[ExternalDependency],
 407→    configs: &[MockConfig],
 408→) -> Vec<MockParam> {
 409→    let config_by_symbol: HashMap<&str, &MockConfig> = configs
 410→        .iter()
 411→        .map(|c| (c.symbol.as_str(), c))
 412→        .collect();
 413→
 414→    let mut result = Vec::new();
 415→
 416→    for dep in deps {
 417→        let category = classify_dependency(dep);
 418→        let has_config = config_by_symbol.contains_key(dep.symbol.as_str());
 419→
 420→        // Pure utilities are passthrough unless explicitly configured
 421→        if category == IoCategory::PureUtility && !has_config {
 422→            continue;
 423→        }
 424→
 425→        let value_source = if has_config {
 426→            ValueSource::UserOverride
 427→        } else {
 428→            ValueSource::AutoGenerated
 429→        };
 430→
 431→        result.push(MockParam {
 432→            symbol: dep.symbol.clone(),
 433→            return_type: dep.return_type.clone(),
 434→            category,
 435→            call_count_estimate: dep.call_sites.len() as u32,
 436→            value_source,
 437→        });
 438→    }
 439→
 440→    result
 441→}
 442→
 443→/// Create [`MockConfig`]s for dependencies discovered at execution time
 444→/// that static analysis missed.
 445→///
 446→/// Converts each [`DiscoveredDependency`] into an [`ExternalDependency`]
 447→/// (with [`TypeInfo::Unknown`] since we have no static type info) and
 448→/// generates a default mock using the standard classification pipeline.
 449→pub fn create_mock_params_for_discovered(
 450→    discovered: &[crate::protocol::DiscoveredDependency],
 451→) -> Vec<MockConfig> {
 452→    discovered
 453→        .iter()
 454→        .map(|dd| {
 455→            let dep = ExternalDependency {
 456→                kind: DependencyKind::FunctionCall,
 457→                symbol: dd.symbol.clone(),
 458→                source_module: dd.source_module.clone(),
 459→                return_type: TypeInfo::Unknown,
 460→                param_types: vec![],
 461→                call_sites: vec![],
 462→            };
 463→            let category = classify_dependency(&dep);
 464→            generate_default_mock(&dep, category)
 465→        })
 466→        .collect()
 467→}
