 469→#[cfg(test)]
 470→mod tests {
 471→    use super::*;
 472→    use crate::protocol::DependencyKind;
 473→
 474→    fn make_dep(symbol: &str, source_module: &str, return_type: TypeInfo) -> ExternalDependency {
 475→        ExternalDependency {
 476→            kind: DependencyKind::FunctionCall,
 477→            symbol: symbol.to_string(),
 478→            source_module: source_module.to_string(),
 479→            return_type,
 480→            param_types: vec![],
 481→            call_sites: vec![1],
 482→        }
 483→    }
 484→
 485→    #[test]
 486→    fn classify_fs_modules() {
 487→        let dep = make_dep("readFile", "fs", TypeInfo::Str);
 488→        assert_eq!(classify_dependency(&dep), IoCategory::FileSystem);
 489→
 490→        let dep2 = make_dep("readFile", "node:fs/promises", TypeInfo::Str);
 491→        assert_eq!(classify_dependency(&dep2), IoCategory::FileSystem);
 492→
 493→        let dep3 = make_dep("join", "path", TypeInfo::Str);
 494→        assert_eq!(classify_dependency(&dep3), IoCategory::FileSystem);
 495→    }
 496→
 497→    #[test]
 498→    fn classify_network_modules() {
 499→        let dep = make_dep("get", "axios", TypeInfo::Unknown);
 500→        assert_eq!(classify_dependency(&dep), IoCategory::Network);
 501→
 502→        let dep2 = make_dep("fetch", "node-fetch", TypeInfo::Unknown);
 503→        assert_eq!(classify_dependency(&dep2), IoCategory::Network);
 504→    }
 505→
 506→    #[test]
 507→    fn classify_database_modules() {
 508→        let dep = make_dep("query", "pg", TypeInfo::Unknown);
 509→        assert_eq!(classify_dependency(&dep), IoCategory::Database);
 510→
 511→        let dep2 = make_dep("findMany", "@prisma/client", TypeInfo::Unknown);
 512→        assert_eq!(classify_dependency(&dep2), IoCategory::Database);
 513→    }
 514→
 515→    #[test]
 516→    fn classify_pure_utility_modules() {
 517→        let dep = make_dep("map", "lodash", TypeInfo::Unknown);
 518→        assert_eq!(classify_dependency(&dep), IoCategory::PureUtility);
 519→
 520→        let dep2 = make_dep("format", "date-fns", TypeInfo::Unknown);
 521→        assert_eq!(classify_dependency(&dep2), IoCategory::PureUtility);
 522→    }
 523→
 524→    #[test]
 525→    fn classify_unknown_module_as_external_other() {
 526→        let dep = make_dep("doSomething", "my-custom-lib", TypeInfo::Int);
 527→        assert_eq!(classify_dependency(&dep), IoCategory::ExternalOther);
 528→    }
 529→
 530→    #[test]
 531→    fn default_mock_for_fs_read() {
 532→        let dep = make_dep("readFile", "fs", TypeInfo::Str);
 533→        let mock = generate_default_mock(&dep, IoCategory::FileSystem);
 534→        assert_eq!(mock.symbol, "readFile");
 535→        assert_eq!(mock.return_values, vec![json!("")]);
 536→        assert!(mock.should_track_calls);
 537→        assert_eq!(mock.default_behavior, MockBehavior::RepeatLast);
 538→    }
 539→
 540→    #[test]
 541→    fn default_mock_for_fs_exists() {
 542→        let dep = make_dep("existsSync", "fs", TypeInfo::Bool);
 543→        let mock = generate_default_mock(&dep, IoCategory::FileSystem);
 544→        assert_eq!(mock.return_values, vec![json!(true)]);
 545→    }
 546→
 547→    #[test]
 548→    fn default_mock_for_network() {
 549→        let dep = make_dep("get", "axios", TypeInfo::Unknown);
 550→        let mock = generate_default_mock(&dep, IoCategory::Network);
 551→        assert_eq!(mock.return_values, vec![json!({"status": 200, "data": {}})]);
 552→        assert!(mock.should_track_calls);
 553→    }
 554→
 555→    #[test]
 556→    fn default_mock_for_db_query() {
 557→        let dep = make_dep("query", "pg", TypeInfo::Unknown);
 558→        let mock = generate_default_mock(&dep, IoCategory::Database);
 559→        assert_eq!(mock.return_values, vec![json!({"rows": []})]);
 560→    }
 561→
 562→    #[test]
 563→    fn default_mock_for_db_insert() {
 564→        let dep = make_dep("insert", "pg", TypeInfo::Unknown);
 565→        let mock = generate_default_mock(&dep, IoCategory::Database);
 566→        assert_eq!(mock.return_values, vec![json!({"rowCount": 1})]);
 567→    }
 568→
 569→    #[test]
 570→    fn default_mock_for_pure_utility_is_passthrough() {
 571→        let dep = make_dep("map", "lodash", TypeInfo::Unknown);
 572→        let mock = generate_default_mock(&dep, IoCategory::PureUtility);
 573→        assert_eq!(mock.default_behavior, MockBehavior::Passthrough);
 574→        assert!(mock.return_values.is_empty());
 575→        assert!(!mock.should_track_calls);
 576→    }
 577→
 578→    #[test]
 579→    fn default_mock_for_external_other_uses_type() {
 580→        let dep = make_dep("compute", "my-lib", TypeInfo::Int);
 581→        let mock = generate_default_mock(&dep, IoCategory::ExternalOther);
 582→        assert_eq!(mock.return_values, vec![json!(0)]);
 583→    }
 584→
 585→    #[test]
 586→    fn default_for_type_object() {
 587→        let typ = TypeInfo::Object {
 588→            fields: vec![
 589→                ("name".to_string(), TypeInfo::Str),
 590→                ("age".to_string(), TypeInfo::Int),
 591→            ],
 592→        };
 593→        let val = default_for_type(&typ);
 594→        assert_eq!(val, json!({"name": "", "age": 0}));
 595→    }
 596→
 597→    #[test]
 598→    fn generate_auto_mocks_skips_existing() {
