 650→    /// Integration test: full auto-mock pipeline for a function with mixed dependencies.
 651→    /// Validates that dependencies are classified, mocks are generated with correct
 652→    /// return values, pure utilities are skipped, and user overrides are applied.
 653→    #[test]
 654→    fn auto_mock_pipeline_mixed_dependencies() {
 655→        // Simulate a function that depends on fs.readFileSync, axios.get,
 656→        // pg.query, lodash.map, and a custom library.
 657→        let deps = vec![
 658→            make_dep("readFileSync", "fs", TypeInfo::Str),
 659→            make_dep("get", "axios", TypeInfo::Unknown),
 660→            make_dep("query", "pg", TypeInfo::Unknown),
 661→            make_dep("map", "lodash", TypeInfo::Unknown),
 662→            make_dep("compute", "my-analytics-lib", TypeInfo::Int),
 663→        ];
 664→
 665→        // User override: custom return value for the database query mock
 666→        let mut overrides = HashMap::new();
 667→        overrides.insert(
 668→            "query".to_string(),
 669→            MockOverride {
 670→                return_values: Some(vec![json!({"rows": [{"id": 1, "name": "alice"}]})]),
 671→                behavior: None,
 672→            },
 673→        );
 674→
 675→        let mocks = generate_auto_mocks(&deps, None, &overrides, &[]);
 676→
 677→        // 4 mocks generated: fs, network, db (overridden), and external other.
 678→        // lodash (pure utility) is skipped.
 679→        assert_eq!(mocks.len(), 4, "expected 4 mocks (lodash skipped)");
 680→
 681→        let by_symbol: HashMap<&str, &MockConfig> =
 682→            mocks.iter().map(|m| (m.symbol.as_str(), m)).collect();
 683→
 684→        // fs.readFileSync → filesystem category, returns ""
 685→        let fs_mock = by_symbol["readFileSync"];
 686→        assert_eq!(fs_mock.return_values, vec![json!("")]);
 687→        assert!(fs_mock.should_track_calls);
 688→        assert_eq!(fs_mock.default_behavior, MockBehavior::RepeatLast);
 689→
 690→        // axios.get → network category, returns {status: 200, data: {}}
 691→        let net_mock = by_symbol["get"];
 692→        assert_eq!(net_mock.return_values, vec![json!({"status": 200, "data": {}})]);
 693→        assert!(net_mock.should_track_calls);
 694→
 695→        // pg.query → database category, but overridden with custom rows
 696→        let db_mock = by_symbol["query"];
 697→        assert_eq!(
 698→            db_mock.return_values,
 699→            vec![json!({"rows": [{"id": 1, "name": "alice"}]})]
 700→        );
 701→        assert!(db_mock.should_track_calls);
 702→
 703→        // my-analytics-lib.compute → external other, type-aware default for Int
 704→        let ext_mock = by_symbol["compute"];
 705→        assert_eq!(ext_mock.return_values, vec![json!(0)]);
 706→        assert!(ext_mock.should_track_calls);
 707→
 708→        // Verify lodash.map is NOT in the mock list
 709→        assert!(!by_symbol.contains_key("map"));
 710→    }
