  1→//! Checks whether a function's parameters contain opaque types,
  2→//! making it unexecutable for automated testing.
  3→
  4→use crate::types::ParamInfo;
  5→
  6→/// Reason why a function parameter cannot be automatically tested.
  7→#[derive(Debug, Clone, PartialEq)]
  8→pub struct SkipReason {
  9→    /// Name of the parameter containing the opaque type.
 10→    pub param_name: String,
 11→    /// Label of the opaque type found (e.g. "net.Socket", "pg.Client").
