 15→/// Checks each parameter for opaque types. Returns a `SkipReason` for every
 16→/// parameter whose type tree contains an `Opaque` node or whose `type_name`
 17→/// matches an entry in `custom_opaque_types`.
 18→#[must_use]
 19→pub fn check_executability(
 20→    params: &[ParamInfo],
 21→    custom_opaque_types: &[String],
 22→) -> Vec<SkipReason> {
 23→    params
 24→        .iter()
 25→        .filter_map(|p| {
 26→            // Check built-in opaque detection first.
 27→            if let Some(label) = p.typ.find_opaque_label() {
 28→                return Some(SkipReason {
 29→                    param_name: p.name.clone(),
 30→                    opaque_label: label,
 31→                });
 32→            }
 33→            // Check user-configured opaque types by type_name.
 34→            if let Some(ref tn) = p.type_name
 35→                && custom_opaque_types.iter().any(|o| o == tn)
 36→            {
 37→                return Some(SkipReason {
 38→                    param_name: p.name.clone(),
 39→                    opaque_label: tn.clone(),
 40→                });
 41→            }
 42→            None
 43→        })
 44→        .collect()
 45→}
