1214→            (ctx.sampled_functions as f64 / ctx.total_functions as f64 * 100.0).round() as usize
1215→        } else {
1216→            0
1217→        };
1218→        out.push_str(&format!(
1219→            "Explored {}/{} functions ({}% core sample, {} via dependency closure)\n",
1220→            ctx.sampled_functions + ctx.closure_functions,
1221→            ctx.total_functions,
1222→            pct,
1223→            ctx.closure_functions,
1224→        ));
