1243→                format_mocks_used(&func_result.mocks_used)
1244→            ));
1245→        }
1246→
1247→        for cov in &func_result.behavior_coverage {
1248→            let exercised = cov.exercised_behavior_ids.len();
1249→            let total = cov.total_behaviors;
1250→            let pct = if total > 0 {
