1267→/// Append "Skipped (expected)" and "Errors" sections to a report string.
1268→fn format_skip_sections(expected: &[&SkippedFunction], errors: &[&SkippedFunction], out: &mut String) {
1269→    if !expected.is_empty() {
1270→        out.push_str(&format!("\nSkipped (expected, {}):\n", expected.len()));
1271→        for skip in expected {
1272→            out.push_str(&format!("  {}: {}\n", skip.function_name, skip.reason));
1273→        }
1274→    }
1275→
1276→    if !errors.is_empty() {
1277→        out.push_str(&format!("\nErrors ({}):\n", errors.len()));
1278→        for skip in errors {
1279→            out.push_str(&format!("  {}: {}\n", skip.function_name, skip.reason));
1280→        }
1281→    }
1282→}
